/* com.matjzing.mapper.FrontExcalendarMapper.insertFrontExcalendar */
INSERT INTO EXCALENDAR (
	  USER_SEQ /**/
	, GOOGLE_CAL_ID /**/
	, ACCESS_TOKEN /**/
	, REFRESH_TOKEN /**/
	, USE_YN /**/
	, REGISTER_SEQ /**/
	, REGISTER_IP /**/
	, REGISTRATION_DT /**/
	, UPDATER_SEQ /**/
	, UPDATER_IP /**/
	, UPDATE_DT /**/
) VALUES (
	  #{userSeq}
	, #{googleCalId}
	, #{accessToken}
	, #{refreshToken}
	, TRUE
	, #{registerSeq}
	, #{registerIp}
	, NOW(3)
	, #{updaterSeq}
	, #{updaterIp}
	, NOW(3)
)
